import{f as i,D as g,o as e,c as p,a2 as r,b as o,w as a,a as s,G as d,a5 as l}from"./chunks/framework.DHYrF-q6.js";const q=JSON.parse('{"title":"多活架构与链路追踪","description":"","frontmatter":{},"headers":[],"relativePath":"high-concurrency/architecture-scaling/multi-active-tracing.md","filePath":"high-concurrency/architecture-scaling/multi-active-tracing.md","lastUpdated":1780917900000}'),h={name:"high-concurrency/architecture-scaling/multi-active-tracing.md"};function u(c,t,E,B,A,C){const n=g("Mermaid");return e(),p("div",null,[t[2]||(t[2]=r('<h1 id="多活架构与链路追踪" tabindex="-1">多活架构与链路追踪 <a class="header-anchor" href="#多活架构与链路追踪" aria-label="Permalink to &quot;多活架构与链路追踪&quot;">​</a></h1><p>创建日期：2026-06-06</p><h2 id="多活架构" tabindex="-1">多活架构 <a class="header-anchor" href="#多活架构" aria-label="Permalink to &quot;多活架构&quot;">​</a></h2><h3 id="问题背景" tabindex="-1">问题背景 <a class="header-anchor" href="#问题背景" aria-label="Permalink to &quot;问题背景&quot;">​</a></h3><p>单机房部署存在风险：机房断电、光纤挖断、自然灾害。如何保证即使一个机房完全不可用，系统仍能对外服务？这就是<strong>多活架构</strong>要解决的问题。</p><h3 id="三种容灾架构" tabindex="-1">三种容灾架构 <a class="header-anchor" href="#三种容灾架构" aria-label="Permalink to &quot;三种容灾架构&quot;">​</a></h3>',6)),(e(),o(l,null,{default:a(()=>[d(n,{id:"mermaid-18",class:"mermaid",graph:"flowchart%20TB%0A%20%20%20%20subgraph%20%E5%90%8C%E5%9F%8E%E5%8F%8C%E6%B4%BB%5B%22%E5%90%8C%E5%9F%8E%E5%8F%8C%E6%B4%BB%22%5D%0A%20%20%20%20%20%20%20%20A1%5B%E6%9C%BA%E6%88%BFA%3Cbr%2F%3E%E6%89%BF%E8%BD%BD50%25%E6%B5%81%E9%87%8F%5D%20%3C--%3E%20A2%5B%E6%9C%BA%E6%88%BFB%3Cbr%2F%3E%E6%89%BF%E8%BD%BD50%25%E6%B5%81%E9%87%8F%5D%0A%20%20%20%20end%0A%0A%20%20%20%20subgraph%20%E4%B8%A4%E5%9C%B0%E4%B8%89%E4%B8%AD%E5%BF%83%5B%22%E4%B8%A4%E5%9C%B0%E4%B8%89%E4%B8%AD%E5%BF%83%22%5D%0A%20%20%20%20%20%20%20%20B1%5B%E5%90%8C%E5%9F%8E%E6%9C%BA%E6%88%BFA%3Cbr%2F%3E100%25%E6%B5%81%E9%87%8F%5D%20%3C--%3E%20B2%5B%E5%90%8C%E5%9F%8E%E6%9C%BA%E6%88%BFB%3Cbr%2F%3E%E7%81%BE%E5%A4%87%5D%0A%20%20%20%20%20%20%20%20B1%20%3C--%3E%20B3%5B%E5%BC%82%E5%9C%B0%E6%9C%BA%E6%88%BFC%3Cbr%2F%3E%E7%81%BE%E5%A4%87%5D%0A%20%20%20%20end%0A%0A%20%20%20%20subgraph%20%E5%BC%82%E5%9C%B0%E5%A4%9A%E6%B4%BB%5B%22%E5%BC%82%E5%9C%B0%E5%A4%9A%E6%B4%BB%22%5D%0A%20%20%20%20%20%20%20%20C1%5B%E5%8C%97%E4%BA%AC%E6%9C%BA%E6%88%BF%3Cbr%2F%3E%E5%8C%97%E6%96%B9%E7%94%A8%E6%88%B7%5D%20%3C..%3E%20C2%5B%E4%B8%8A%E6%B5%B7%E6%9C%BA%E6%88%BF%3Cbr%2F%3E%E5%8D%8E%E4%B8%9C%E7%94%A8%E6%88%B7%5D%0A%20%20%20%20%20%20%20%20C1%20%3C..%3E%20C3%5B%E5%B9%BF%E5%B7%9E%E6%9C%BA%E6%88%BF%3Cbr%2F%3E%E5%8D%8E%E5%8D%97%E7%94%A8%E6%88%B7%5D%0A%20%20%20%20end%0A%0A%20%20%20%20style%20%E5%90%8C%E5%9F%8E%E5%8F%8C%E6%B4%BB%20fill%3A%23e8f5e9%2Cstroke%3A%234caf50%0A%20%20%20%20style%20%E4%B8%A4%E5%9C%B0%E4%B8%89%E4%B8%AD%E5%BF%83%20fill%3A%23fff3e0%2Cstroke%3A%23ff9800%0A%20%20%20%20style%20%E5%BC%82%E5%9C%B0%E5%A4%9A%E6%B4%BB%20fill%3A%23e3f2fd%2Cstroke%3A%232196f3%0A"})]),fallback:a(()=>[...t[0]||(t[0]=[s(" Loading... ",-1)])]),_:1})),t[3]||(t[3]=r('<table tabindex="0"><thead><tr><th>架构</th><th>机房距离</th><th>故障切换时间</th><th>成本</th><th>适用场景</th></tr></thead><tbody><tr><td><strong>同城双活</strong></td><td>&lt; 50km</td><td>秒级（自动）</td><td>中</td><td>普通互联网业务</td></tr><tr><td><strong>两地三中心</strong></td><td>同城+异地</td><td>分钟级（同城）/ 手动（异地）</td><td>高</td><td>金融、关键业务</td></tr><tr><td><strong>异地多活</strong></td><td>跨城市</td><td>秒级（自动就近接入）</td><td>最高</td><td>大型互联网公司</td></tr></tbody></table><h3 id="多活核心挑战" tabindex="-1">多活核心挑战 <a class="header-anchor" href="#多活核心挑战" aria-label="Permalink to &quot;多活核心挑战&quot;">​</a></h3><h4 id="_1-数据同步冲突" tabindex="-1">1. 数据同步冲突 <a class="header-anchor" href="#_1-数据同步冲突" aria-label="Permalink to &quot;1. 数据同步冲突&quot;">​</a></h4><p>两个机房同时修改同一条数据，怎么解决？</p><table tabindex="0"><thead><tr><th>方案</th><th>原理</th><th>适用场景</th></tr></thead><tbody><tr><td><strong>单元化</strong></td><td>按用户 ID 分片，每个用户只路由到一个机房</td><td>用户数据可分区（推荐）</td></tr><tr><td><strong>最后写入胜（LWW）</strong></td><td>以时间戳为准，最新数据覆盖</td><td>冲突不敏感的场景</td></tr><tr><td><strong>CRDT</strong></td><td>无冲突复制数据类型，自动合并</td><td>计数器、集合等特定场景</td></tr><tr><td><strong>业务层补偿</strong></td><td>冲突后异步对比和修复</td><td>对一致性敏感的场景</td></tr></tbody></table><h4 id="_2-用户路由" tabindex="-1">2. 用户路由 <a class="header-anchor" href="#_2-用户路由" aria-label="Permalink to &quot;2. 用户路由&quot;">​</a></h4><p>用户应该访问哪个机房？</p><p><strong>GSLB（全局负载均衡）：</strong></p><ul><li>用户 DNS 解析 → GSLB 根据 IP 返回最近机房的地址。</li><li>机房故障时，GSLB 将流量切到健康机房。</li><li>支持就近接入 + 故障切换。</li></ul><h4 id="_3-故障切换" tabindex="-1">3. 故障切换 <a class="header-anchor" href="#_3-故障切换" aria-label="Permalink to &quot;3. 故障切换&quot;">​</a></h4><p>机房故障时，如何将流量切到其他机房？</p><ul><li><strong>GSLB 切换</strong>：修改 DNS 解析，将故障机房 IP 替换为备用机房。</li><li><strong>数据补偿</strong>：故障期间的数据变更，需要回放或补偿。</li><li><strong>容量预留</strong>：备用机房需要预留足够的容量，不能满负荷运行。</li></ul><h2 id="链路追踪" tabindex="-1">链路追踪 <a class="header-anchor" href="#链路追踪" aria-label="Permalink to &quot;链路追踪&quot;">​</a></h2><h3 id="为什么需要链路追踪" tabindex="-1">为什么需要链路追踪？ <a class="header-anchor" href="#为什么需要链路追踪" aria-label="Permalink to &quot;为什么需要链路追踪？&quot;">​</a></h3><p>微服务架构下，一个请求可能经过十几个服务。如果某个请求慢了或失败了，如何快速定位是哪一环出了问题？</p><div class="tip custom-block"><p class="custom-block-title">核心问题</p><ul><li>请求经过了哪些服务？</li><li>每个服务耗时多少？</li><li>哪个环节是瓶颈？</li></ul></div><h3 id="核心原理" tabindex="-1">核心原理 <a class="header-anchor" href="#核心原理" aria-label="Permalink to &quot;核心原理&quot;">​</a></h3>',17)),(e(),o(l,null,{default:a(()=>[d(n,{id:"mermaid-243",class:"mermaid",graph:"sequenceDiagram%0A%20%20%20%20participant%20A%20as%20%E6%9C%8D%E5%8A%A1A%0A%20%20%20%20participant%20B%20as%20%E6%9C%8D%E5%8A%A1B%0A%20%20%20%20participant%20C%20as%20%E6%9C%8D%E5%8A%A1C%0A%0A%20%20%20%20Note%20over%20A%3A%20%E7%94%9F%E6%88%90%20TraceId%3Dabc%0A%0A%20%20%20%20A-%3E%3EA%3A%20SpanA%20(TraceId%3Dabc%2C%20SpanId%3D1)%0A%20%20%20%20A-%3E%3EB%3A%20HTTP%20%2B%20Header(TraceId%3Dabc%2C%20ParentSpanId%3D1)%0A%0A%20%20%20%20B-%3E%3EB%3A%20SpanB%20(TraceId%3Dabc%2C%20SpanId%3D2%2C%20Parent%3D1)%0A%20%20%20%20B-%3E%3EC%3A%20HTTP%20%2B%20Header(TraceId%3Dabc%2C%20ParentSpanId%3D2)%0A%0A%20%20%20%20C-%3E%3EC%3A%20SpanC%20(TraceId%3Dabc%2C%20SpanId%3D3%2C%20Parent%3D2)%0A%20%20%20%20C--%3E%3EB%3A%20%E5%93%8D%E5%BA%94%0A%20%20%20%20B--%3E%3EA%3A%20%E5%93%8D%E5%BA%94%0A"})]),fallback:a(()=>[...t[1]||(t[1]=[s(" Loading... ",-1)])]),_:1})),t[4]||(t[4]=r(`<p><strong>核心概念：</strong></p><table tabindex="0"><thead><tr><th>概念</th><th>含义</th><th>图示</th></tr></thead><tbody><tr><td><strong>TraceId</strong></td><td>一次完整请求链路的唯一标识</td><td>整个请求链使用同一个 TraceId</td></tr><tr><td><strong>SpanId</strong></td><td>一个服务调用的唯一标识</td><td>每个服务处理生成一个 SpanId</td></tr><tr><td><strong>ParentSpanId</strong></td><td>父调用的 SpanId</td><td>形成调用链父子关系</td></tr></tbody></table><h3 id="传播方式" tabindex="-1">传播方式 <a class="header-anchor" href="#传播方式" aria-label="Permalink to &quot;传播方式&quot;">​</a></h3><p>服务间调用时，TraceId 和 SpanId 通过 HTTP Header 传递：</p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>X-B3-TraceId: abc123</span></span>
<span class="line"><span>X-B3-SpanId: def456</span></span>
<span class="line"><span>X-B3-ParentSpanId: abc123</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br></div></div><h3 id="主流框架对比" tabindex="-1">主流框架对比 <a class="header-anchor" href="#主流框架对比" aria-label="Permalink to &quot;主流框架对比&quot;">​</a></h3><table tabindex="0"><thead><tr><th>框架</th><th>存储</th><th>UI</th><th>采样策略</th><th>适用场景</th></tr></thead><tbody><tr><td><strong>Jaeger</strong></td><td>Elasticsearch/Cassandra</td><td>自带 UI</td><td>支持</td><td>通用（CNCF 项目）</td></tr><tr><td><strong>Zipkin</strong></td><td>MySQL/ES/Cassandra</td><td>自带 UI</td><td>支持</td><td>Spring Cloud 集成好</td></tr><tr><td><strong>SkyWalking</strong></td><td>ES/H2/MySQL</td><td>自带 UI + 拓扑图</td><td>支持</td><td>Java 生态，自带 Agent</td></tr><tr><td><strong>OpenTelemetry</strong></td><td>标准（不绑定后端）</td><td>无（需对接后端）</td><td>支持</td><td>标准 API，未来趋势</td></tr></tbody></table><h3 id="opentelemetry" tabindex="-1">OpenTelemetry <a class="header-anchor" href="#opentelemetry" aria-label="Permalink to &quot;OpenTelemetry&quot;">​</a></h3><p>OpenTelemetry 是 CNCF 的<strong>可观测性标准</strong>，统一了 Trace、Metrics、Logs 的数据采集和导出。不是具体的存储/UI 方案，而是一套标准 API + SDK + Collector。</p><p><strong>核心价值：</strong> 一套 API 对接多个后端（Jaeger、Zipkin、Prometheus），不被供应商锁定。</p><hr><h2 id="经典高频面试题" tabindex="-1">经典高频面试题 <a class="header-anchor" href="#经典高频面试题" aria-label="Permalink to &quot;经典高频面试题&quot;">​</a></h2><h3 id="q1-同城双活、两地三中心、异地多活有什么区别" tabindex="-1">Q1：同城双活、两地三中心、异地多活有什么区别？ <a class="header-anchor" href="#q1-同城双活、两地三中心、异地多活有什么区别" aria-label="Permalink to &quot;Q1：同城双活、两地三中心、异地多活有什么区别？&quot;">​</a></h3><p><strong>知识要点：</strong> 三种容灾架构在机房距离、切换速度、成本上的维次差异。</p><p><strong>我们当时给一个中型电商做架构评审时，业务方PM提的需求是&quot;系统绝对不能挂&quot;，预算只有50万。</strong> 异地多活至少要3个机房，光专线费一年就40万+，更不用说数据同步中间件的成本。我们跟PM解释说同城双活就够了——两个机房都在上海，距离30km，光纤延迟1ms，一台核心交换机宕了另一机房秒级接管。PM不理解为什么不做异地多活，我们拿12306举例子：人家是因为春运期间一个机房扛不住所有流量才需要异地多活，你日均UV才50万，同城双活绰绰有余。</p><p><strong>踩坑经历：</strong> 同城双活上线后第一周就出了事故——两个机房之间的光纤被施工挖断了，但不是两根都断而是只断了一根。由于两个机房之间通信中断了3分钟，两边各自以为对方挂了，同时抢主，结果出现脑裂——两个机房都开始处理写请求。虽然最终只持续了3分钟，但造成了约200笔订单的库存数据不一致。修复方案是加了&quot;第三方仲裁节点&quot;（一个低配ECS部署在阿里云第三个可用区，专门做心跳监测）。</p><p><strong>量化结果：</strong> 同城双活方案总投入48万（vs.异地多活预估230万），上线后年度可用性从99.9%提升到99.97%（年度不可用时间从8.7小时降到2.6小时）。唯一一次光纤中断17分钟，GSLB在40秒内完成切换，用户侧无明显感知。</p><p><strong>面试官追问：</strong></p><ul><li><strong>追问1：</strong> &quot;同城双活和两地三中心，一般都怎么选？&quot; —— 看业务类型和预算。我们当时的判断标准：金融支付类必须两地三中心（监管要求异地灾备），电商交易类同城双活够用，内容资讯类甚至单机房+异地冷备就够。核心指标是RTO（恢复时间目标）：同城双活RTO通常是秒级，两地三中心本地秒级/异地分钟级。</li><li><strong>追问2：</strong> &quot;脑裂怎么检测？不用第三方仲裁行不行？&quot; —— 理论上可以用多数派算法（3个机房2个可用就继续服务），但同城双活只有2个机房做不到多数派。所以必须引入第三个决策者——可以是独立的仲裁服务，也可以依赖外部存储（如一个共享的Redis/etcd集群），谁先拿到锁谁做主。</li></ul><h3 id="q2-多活架构数据同步冲突怎么解决" tabindex="-1">Q2：多活架构数据同步冲突怎么解决？ <a class="header-anchor" href="#q2-多活架构数据同步冲突怎么解决" aria-label="Permalink to &quot;Q2：多活架构数据同步冲突怎么解决？&quot;">​</a></h3><p><strong>知识要点：</strong> 单元化（按用户分片）、LWW（时间戳覆盖）、CRDT（自动合并）、业务补偿四种方案。</p><p><strong>我们在用户中心多活改造时，选择了单元化方案——按user_id哈希把用户路由到固定机房。</strong> 这个方案逻辑上最完美：每个用户只有一个&quot;家&quot;，不存在跨机房写冲突。理论完美但实际落地遇到两个恶心的问题：一是VIP用户（头部商家）的数据量是普通用户的1000倍+，导致hash分布严重不均，北京机房一个VIP用户的数据量等于广州机房1000个普通用户。</p><p><strong>踩坑经历：</strong> VIP数据倾斜导致北京机房的Redis内存使用率83%，广州只有32%。解决方案是做&quot;大用户拆分&quot;——将VIP用户的子业务拆分（如订单、商品、评价分别路由到不同机房），在应用层做数据聚合。第二个坑是用户漫游——用户出差从北京到了广州，GSLB就近接入把他路由到广州机房，但数据在北京机房，每次请求跨机房调用的延迟多了30ms。通过动态路由表（用户漫游时更新DNS权重指向原始机房）解决了这个问题。</p><p><strong>量化结果：</strong> 单元化+大用户拆分后，三个机房的资源利用率偏差从原来的51个百分点降到8个百分点。跨机房RPC调用比例从12%降到3%。用户漫游场景的P99延迟从180ms降到65ms。</p><p><strong>面试官追问：</strong></p><ul><li><strong>追问1：</strong> &quot;单元化如果用户换手机号或换设备怎么办？会不会换机房？&quot; —— 不会，单元化路由key是user_id，跟手机号/设备无关。除非用户注册新账号，否则始终在同一个机房。我们甚至在注册时就预分配了机房（根据注册时的IP归属地+哈希），后期从不迁移。</li><li><strong>追问2：</strong> &quot;如果某个机房容量满了怎么办？能不能把部分用户迁移到其他机房？&quot; —— 这就是单元化的代价——迁移用户数据成本很高。我们的做法是提前设置容量水位线（75%），达到后就扩容该机房的资源而不是迁移用户。如果真的需要迁移（如机房裁撤），需要做全量数据同步+双写过渡期（至少2周），然后切路由。</li></ul><h3 id="q3-gslb-如何做到就近接入和故障切换" tabindex="-1">Q3：GSLB 如何做到就近接入和故障切换？ <a class="header-anchor" href="#q3-gslb-如何做到就近接入和故障切换" aria-label="Permalink to &quot;Q3：GSLB 如何做到就近接入和故障切换？&quot;">​</a></h3><p><strong>知识要点：</strong> GSLB通过智能DNS根据用户源IP返回最近机房的地址，故障时自动切换。</p><p><strong>我们用阿里云的GSLB（全局流量管理）做就近接入。</strong> 初期配置很简单：北京用户→北京机房，上海用户→上海机房。但有个用户投诉说他家宽带是北京电信，每次访问网站却路由到了广州机房——排查发现他的DNS服务器IP被GSLB的IP库误判成了广东。</p><p><strong>踩坑经历：</strong> DNS IP库的准确率大约95%，总有5%的用户会被错误路由。我们的解决是加了&quot;二次校验&quot;——用户首次访问时，前端测速（ping三个机房的静态资源URL），把延迟最低的机房写入Cookie，后续请求优先用Cookie中的机房。DNS解析是粗粒度分流（95%准确率），Cookie是精确优化（覆盖剩下的5%）。</p><p><strong>量化结果：</strong> 二次校验上线后，用户页面加载时间P50从1.5秒降到900ms，P99从4.2秒降到2.1秒。被错误路由的用户比例从5%降到0.3%以下。故障切换时间平均35秒（GSLB TTL设为30秒+切换检测5秒）。</p><p><strong>面试官追问：</strong></p><ul><li><strong>追问1：</strong> &quot;DNS切换有缓存，TTL设多少合适？设太小会怎样？&quot; —— TTL是双刃剑：设太小（如10秒），切换快但DNS查询量暴增（用户每次访问都查DNS）；设太大（如300秒），故障时切换慢。我们折中设30秒，这30秒虽然有小部分用户可能访问到故障机房，但前端有重试机制（3次）和降级页，整体可用性没影响。</li><li><strong>追问2：</strong> &quot;有没有比DNS切换更快的方案？&quot; —— 有，Anycast（任播）IP方案，所有机房同一个IP，由BGP路由自动选择最近路径，故障时路由自动收敛。速度秒级但成本是DNS方案的5-10倍，且需要自有AS号和IP段。大型云厂商（AWS/Azure）默认就是Anycast。</li></ul><h3 id="q4-链路追踪的核心原理是什么-traceid-和-spanid-是什么" tabindex="-1">Q4：链路追踪的核心原理是什么？TraceId 和 SpanId 是什么？ <a class="header-anchor" href="#q4-链路追踪的核心原理是什么-traceid-和-spanid-是什么" aria-label="Permalink to &quot;Q4：链路追踪的核心原理是什么？TraceId 和 SpanId 是什么？&quot;">​</a></h3><p><strong>知识要点：</strong> TraceId标识一次完整请求链路，SpanId标识单个服务调用，ParentSpanId形成父子调用关系。</p><p><strong>我们在排查一个P0故障时深刻体会到链路追踪的价值。</strong> 用户反馈下单接口偶发性超时（概率约2%），查日志看不出规律。接入了SkyWalking以后，过滤出所有超过3秒的Trace，发现了一个共同模式：所有超时请求都经过了促销服务的&quot;计算优惠券&quot;环节，而那个环节里有一个Redis的ZRANGEBYSCORE操作耗时800-1200ms。</p><p><strong>踩坑经历：</strong> 没有链路追踪之前排查类似问题要花2-4小时（各个服务的日志肉眼关联），有了链路追踪后5分钟定位到瓶颈。但链路追踪本身也有开销——我们初期全量采样（100%采样率），结果SkyWalking Agent消耗了应用8%的CPU，而且ES存储每天产生80GB数据，2周就爆满了。后来改成&quot;正常请求采样10%，异常请求采样100%&quot;，开销降到1.5% CPU，存储降到每天8GB。</p><p><strong>量化结果：</strong> 链路追踪上线后，故障平均定位时间从2.2小时降到12分钟（缩短90%）。超时接口瓶颈识别准确率从人工排查的60%提升到95%。应用性能开销控制在1.5% CPU以内。</p><p><strong>面试官追问：</strong></p><ul><li><strong>追问1：</strong> &quot;TraceId怎么生成和传播的？如果中间某个服务没接入追踪，链路会断吗？&quot; —— TraceId由入口服务生成（通常用雪花算法或UUID），通过HTTP Header（如<code>X-B3-TraceId</code>）或RPC的Metadata透传。如果中间某个服务没接入，链路确实会断——表现为一个Span的调用关系缺失。SkyWalking通过Agent字节码增强，理论上零侵入，但自定义框架需要手动埋点。</li><li><strong>追问2：</strong> &quot;采样策略除了按比例，还有什么高级策略？&quot; —— 我们用的&quot;自适应采样&quot;：正常请求10%，响应时间&gt;1秒的100%采样，错误请求100%采样，特定userId（VIP用户）100%采样。还可以用&quot;尾部采样&quot;——先把所有Span收集到本地Buffer，只保留耗时Top N的Trace上传到后端。</li></ul><h3 id="q5-opentelemetry-是什么-和-jaeger-skywalking-什么关系" tabindex="-1">Q5：OpenTelemetry 是什么？和 Jaeger/SkyWalking 什么关系？ <a class="header-anchor" href="#q5-opentelemetry-是什么-和-jaeger-skywalking-什么关系" aria-label="Permalink to &quot;Q5：OpenTelemetry 是什么？和 Jaeger/SkyWalking 什么关系？&quot;">​</a></h3><p><strong>知识要点：</strong> OpenTelemetry是CNCF可观测性标准（API/SDK/Collector），Jaeger/SkyWalking是后端实现。</p><p><strong>我们在选型时纠结过要直接用SkyWalking还是走OpenTelemetry路线。</strong> 项目技术栈是Java微服务，SkyWalking几乎开箱即用，Java Agent一键部署。但有一个需求是前端（Node.js）和后端（Java）要做全链路打通，SkyWalking对Node.js支持很弱。另外运维想统一把Trace数据接入已有的Prometheus+Grafana体系，SkyWalking的数据格式不兼容。</p><p><strong>踩坑经历：</strong> 选型结果是&quot;OpenTelemetry SDK + Jaeger后端&quot;：Java服务通过OpenTelemetry Java Agent自动采集，前端Node.js通过OpenTelemetry JS SDK手动埋点。但接入过程中踩了个版本兼容的坑——OpenTelemetry的trace和metrics分属两个不同的API包，版本必须严格对齐，否则Collector会丢弃数据。我们曾经因为<code>opentelemetry-api</code>是1.25而<code>opentelemetry-exporter-otlp</code>是1.27，导致Trace数据丢失了3天才发现。</p><p><strong>量化结果：</strong> OpenTelemetry方案让前端监控也接入了后端Trace体系，端到端链路可见性从纯后端（13个服务）扩展到全栈（前端+13后端+2个中间件）。借助Grafana的统一Dashboard，跨团队的故障排查沟通时间从平均40分钟降到15分钟。</p><p><strong>面试官追问：</strong></p><ul><li><strong>追问1：</strong> &quot;OpenTelemetry Collector和直接发到Jaeger有什么区别？&quot; —— Collector相当于中间缓冲层，可以做数据过滤、聚合、路由、重试。我们用它做了三件事：采样策略统一管理、数据脱敏（过滤手机号等敏感字段）、多后端分发（一份数据同时发给Jaeger和Prometheus）。没有Collector的话，这些逻辑要分散在各个SDK里实现。</li><li><strong>追问2：</strong> &quot;如果从SkyWalking迁移到OpenTelemetry，成本有多大？&quot; —— 我们评估过，代价不小。SkyWalking用的是自己的协议和探针，迁移需要改所有服务的SDK依赖、重新配置采样策略、调整Dashboard。如果SkyWalking跑得挺好，没有多语言需求或统一监控体系需求，不建议迁移。</li></ul><h3 id="q6-skywalking-和-jaeger-怎么选" tabindex="-1">Q6：SkyWalking 和 Jaeger 怎么选？ <a class="header-anchor" href="#q6-skywalking-和-jaeger-怎么选" aria-label="Permalink to &quot;Q6：SkyWalking 和 Jaeger 怎么选？&quot;">​</a></h3><p><strong>知识要点：</strong> SkyWalking适合Java生态（Agent零侵入+拓扑图），Jaeger适合多语言/云原生。</p><p><strong>我们两个团队分别用了SkyWalking和Jaeger，正好可以做个对比。</strong> A团队是纯Java Spring Cloud微服务，用SkyWalking，从接入到看到拓扑图只花了30分钟，几乎零配置。B团队是多语言（Java+Go+Python），用Jaeger+OpenTelemetry，接入花了2天（每种语言SDK配置不同），但效果出来后的优势是Go和Python的调用也都能追踪到。</p><p><strong>踩坑经历：</strong> SkyWalking最大的坑是在大规模场景下的Agent性能——当时A团队部署了200个Java实例，SkyWalking OAP Server（后端分析服务）的堆内存设了8G还是经常OOM，追查发现是因为打开了&quot;SQL参数采集&quot;，每个SQL的参数都上报，ES写入量翻了三倍。关掉SQL参数采集后OAP内存降到3G。Jaeger的坑是它默认存储用Cassandra（运维很重），换成Elasticsearch后查询速度反而慢了（因为ES对时序数据的写入优化不如Cassandra）。</p><p><strong>量化结果：</strong> 两个方案最终性能对比：SkyWalking（Java）Agent overhead 1.2% CPU；Jaeger+OTel（Java）Agent overhead 1.8% CPU但覆盖了多语言。存储成本：SkyWalking ES每天15GB，Jaeger ES每天18GB（多语言采样数据更多）。</p><p><strong>面试官追问：</strong></p><ul><li><strong>追问1：</strong> &quot;SkyWalking能追踪MQ消息吗？&quot; —— 能但需要配置。SkyWalking通过&quot;跨进程传播协议&quot;支持Kafka/RabbitMQ的追踪，在消息Header中注入Trace上下文，消费者消费时提取。我们用它追过一条订单消息在MQ里排队了15分钟才被消费的故障——没有追踪工具这种问题几乎不可能定位。</li><li><strong>追问2：</strong> &quot;微服务200+个以后，链路追踪图会不会很乱？&quot; —— 会。SkyWalking的拓扑图在200+节点时几乎没法看。我们的做法是按业务域拆分视图——订单域一张图、支付域一张图，跨域调用通过服务依赖分析单独查看。另外，不要只看拓扑图，要学会用&quot;慢Trace分析&quot;和&quot;依赖热力图&quot;这两个更实用的视角。</li></ul>`,54))])}const b=i(h,[["render",u]]);export{q as __pageData,b as default};
